function dastInterp(score) {
  if (score===0) return {level:"None Reported",color:"#8b949e",bg:"#161b22",border:"#30363d",action:"No intervention indicated at this time."};
  if (score<=2) return {level:"Low",color:"#3fb950",bg:"#0f2018",border:"#2ea043",action:"Monitor. Provide brief education on drug use risks and available local resources."};
  if (score<=5) return {level:"Moderate",color:"#f0883e",bg:"#2d1e0e",border:"#b45309",action:"Further investigation warranted. Recommend formal assessment and referral to outpatient services."};
  if (score<=8) return {level:"Substantial",color:"#ffa657",bg:"#2d1a0e",border:"#d97706",action:"Assessment and treatment referral strongly recommended. Patient likely needs structured treatment."};
  return {level:"Severe",color:"#f85149",bg:"#2d0f0f",border:"#f85149",action:"Immediate referral to treatment or detox recommended. High-intensity intervention needed."};
}

function fmtDate(iso) {
  return new Date(iso).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"});
}

// localStorage helpers (replaces window.storage for deployment)
function lsGet(key) {
  try { const v = localStorage.getItem(key); return v ? v : null; } catch(e) { return null; }
}
function lsSet(key, val) {
  try { localStorage.setItem(key, val); } catch(e) {}
}

