  const [county, setCounty] = useState("Allegheny");
  const [countyOpen, setCountyOpen] = useState(false);
  const [filterType, setFilterType] = useState("All");
  const [filterSearch, setFilterSearch] = useState("");
  const [selRes, setSelRes] = useState(null);
  const [encounters, setEncounters] = useState([]);
  const [form, setForm] = useState({agency:"",date:new Date().toISOString().split("T")[0],callType:"",substance:"",resourceId:"",outcome:"",notes:"",dastScore:""});
  const [formStatus, setFormStatus] = useState(null);
  const [dastAns, setDastAns] = useState({});
  const [dastScore, setDastScore] = useState(null);
  const [dastDone, setDastDone] = useState(false);
  const [dastSent, setDastSent] = useState(false);

  useEffect(() => {
    const enc = lsGet("enc"); if (enc) setEncounters(JSON.parse(enc));
    const c = lsGet("county"); if (c) setCounty(c);
    const t = setTimeout(() => setSplash(false), 2800);
    return () => clearTimeout(t);
  }, []);

  function pickCounty(c) { setCounty(c); setCountyOpen(false); lsSet("county", c); }
  function saveEnc(u) { setEncounters(u); lsSet("enc", JSON.stringify(u)); }

  const filtered = RESOURCES.filter(r => {
    const mt = filterType === "All" || r.type === filterType;
    const q = filterSearch.toLowerCase();
    const ms = !q || r.name.toLowerCase().includes(q) || r.services.some(s => s.toLowerCase().includes(q));
    return mt && ms;
  });

  function submitEnc() {
    if (!form.agency || !form.callType || !form.outcome) { setFormStatus("err"); return; }
    const entry = {...form, county, id:Date.now(), timestamp:new Date().toISOString()};
    saveEnc([entry, ...encounters]);
    setForm({agency:"",date:new Date().toISOString().split("T")[0],callType:"",substance:"",resourceId:"",outcome:"",notes:"",dastScore:""});
    setFormStatus("ok");
    setTimeout(() => setFormStatus(null), 3000);
  }

  function answerDast(qid, val) {
    const u = {...dastAns, [qid]:val};
    setDastAns(u);
    if (Object.keys(u).length === 10) {
      let s = 0;
      DAST.forEach(q => { const a = u[q.id]; if (q.rev) { if (a==="no") s++; } else { if (a==="yes") s++; } });
      setDastScore(s); setDastDone(true);
    } else { setDastDone(false); setDastScore(null); }
  }
  function resetDast() { setDastAns({}); setDastDone(false); setDastScore(null); setDastSent(false); }
  function sendDast() { setForm(f => ({...f, dastScore:String(dastScore)})); setDastSent(true); setView("log"); }

  const total = encounters.length;
  const accepted = encounters.filter(e => e.outcome.includes("Accepted")).length;
  const transported = encounters.filter(e => e.outcome.includes("Transported")).length;
  const acceptRate = total ? Math.round((accepted/total)*100) : 0;
  const resCounts = {};
  encounters.forEach(e => { if (e.resourceId) { const r = RESOURCES.find(x => x.id===parseInt(e.resourceId)); const n = r?r.name:"Unknown"; resCounts[n] = (resCounts[n]||0)+1; } });
  const topRes = Object.entries(resCounts).sort((a,b) => b[1]-a[1]).slice(0,5);
  const ctCounts = {};
  encounters.forEach(e => { if (e.callType) ctCounts[e.callType] = (ctCounts[e.callType]||0)+1; });
  const dastEncs = encounters.filter(e => e.dastScore !== "" && e.dastScore !== undefined);
  const avgDast = dastEncs.length ? (dastEncs.reduce((s,e) => s+parseInt(e.dastScore),0)/dastEncs.length).toFixed(1) : null;
  const interp = dastScore !== null ? dastInterp(dastScore) : null;
